# CONVERSION FUNCTIONS
# =============================================================================


def _adf_linkedservice_to_nested(
    adf_linkedservice: AdfLinkedservice,
) -> AdfLinkedserviceNested:
    """Convert flat AdfLinkedservice to nested format."""
    attrs = AdfLinkedserviceAttributes()
    _populate_adf_linkedservice_attrs(attrs, adf_linkedservice)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        adf_linkedservice,
        _ADF_LINKEDSERVICE_REL_FIELDS,
        AdfLinkedserviceRelationshipAttributes,
    )
    return AdfLinkedserviceNested(
        guid=adf_linkedservice.guid,
        type_name=adf_linkedservice.type_name,
        status=adf_linkedservice.status,
        version=adf_linkedservice.version,
        create_time=adf_linkedservice.create_time,
        update_time=adf_linkedservice.update_time,
        created_by=adf_linkedservice.created_by,
        updated_by=adf_linkedservice.updated_by,
        classifications=adf_linkedservice.classifications,
        classification_names=adf_linkedservice.classification_names,
        meanings=adf_linkedservice.meanings,
        labels=adf_linkedservice.labels,
        business_attributes=adf_linkedservice.business_attributes,
        custom_attributes=adf_linkedservice.custom_attributes,
        pending_tasks=adf_linkedservice.pending_tasks,
        proxy=adf_linkedservice.proxy,
        is_incomplete=adf_linkedservice.is_incomplete,
        provenance_type=adf_linkedservice.provenance_type,
        home_id=adf_linkedservice.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _adf_linkedservice_from_nested(nested: AdfLinkedserviceNested) -> AdfLinkedservice:
    """Convert nested format to flat AdfLinkedservice."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else AdfLinkedserviceAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _ADF_LINKEDSERVICE_REL_FIELDS,
        AdfLinkedserviceRelationshipAttributes,
    )
    return AdfLinkedservice(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_adf_linkedservice_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _adf_linkedservice_to_nested_bytes(
    adf_linkedservice: AdfLinkedservice, serde: Serde
) -> bytes:
    """Convert flat AdfLinkedservice to nested JSON bytes."""
    return serde.encode(_adf_linkedservice_to_nested(adf_linkedservice))


def _adf_linkedservice_from_nested_bytes(data: bytes, serde: Serde) -> AdfLinkedservice:
    """Convert nested JSON bytes to flat AdfLinkedservice."""
    nested = serde.decode(data, AdfLinkedserviceNested)
    return _adf_linkedservice_from_nested(nested)


